/**
 * List filter session — rule: Linm.Development.Rules/web-app/rule/list-filter-session.md
 */

export const LIST_FILTER_SESSION_VERSION = 1;

export const MFE_LIST_FILTER_NS = 'erp-finance';

export type ListFilterAuthScope = string;

import type { DatePreset } from '@linm-soft/common-components';

export interface VoucherListFilterSession {
  fromDate?: string;
  toDate?: string;
  /** Loại Thời gian (DateRangeFilter) — SSOT cùng from/to */
  datePreset?: DatePreset;
  search?: string;
  status?: string;
  processingLevel?: string;
  page?: number;
}

export function buildListFilterAuthScope(
  userId: string | undefined,
  companyId: string | undefined,
): ListFilterAuthScope {
  return `${userId ?? 'anon'}:${companyId ?? 'no-company'}`;
}

function storagePrefix(mfeId: string): string {
  return `linm.${mfeId}.listFilter.v${LIST_FILTER_SESSION_VERSION}`;
}

function storageKey(
  mfeId: string,
  listScope: string,
  auth: ListFilterAuthScope,
): string {
  return `${storagePrefix(mfeId)}.${auth}.${listScope}`;
}

export function readListFilterSession<T>(
  mfeId: string,
  listScope: string,
  auth: ListFilterAuthScope,
): T | null {
  if (typeof sessionStorage === 'undefined') return null;
  try {
    const raw = sessionStorage.getItem(storageKey(mfeId, listScope, auth));
    if (!raw) return null;
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}

export function writeListFilterSession<T>(
  mfeId: string,
  listScope: string,
  auth: ListFilterAuthScope,
  value: T,
): void {
  if (typeof sessionStorage === 'undefined') return;
  try {
    sessionStorage.setItem(storageKey(mfeId, listScope, auth), JSON.stringify(value));
  } catch {
    // quota — ignore
  }
}

export function clearMfeListFilterSessions(mfeId: string): void {
  if (typeof sessionStorage === 'undefined') return;
  const prefix = `${storagePrefix(mfeId)}.`;
  const keys: string[] = [];
  for (let i = 0; i < sessionStorage.length; i++) {
    const k = sessionStorage.key(i);
    if (k?.startsWith(prefix)) keys.push(k);
  }
  keys.forEach(k => sessionStorage.removeItem(k));
}

export function getDefaultVoucherListDateRange(): { fromDate: string; toDate: string } {
  const today = new Date().toISOString().slice(0, 10);
  return { fromDate: today, toDate: today };
}
